const body = $input.first().json.body || $input.first().json;
const crypto = require('crypto');
const jobId = crypto.randomUUID();

let repoUrl = body.repoUrl || '';
let repoName = body.repoName || '';
let owner = body.owner || '';
const token = body.token || '';

// Auto-extract owner/repoName from URL if not provided
if (repoUrl && (!repoName || !owner)) {
  const match = repoUrl.match(/github\.com\/([^\/]+)\/([^\/]+)/);
  if (match) {
    owner = owner || match[1];
    repoName = repoName || match[2].replace(/\.git$/, '');
  }
}

if (!repoName || !owner) {
  throw new Error('Missing required fields: owner and repoName (or valid GitHub repoUrl)');
}

return [{
  json: {
    jobId,
    repoUrl: repoUrl || `https://github.com/${owner}/${repoName}`,
    repoName,
    owner,
    token,
    startedAt: new Date().toISOString()
  }
}];

const input = $('Extract Input').item.json;
const repoInfo = $('Get Repo Info').item.json;
const treeData = $('Get File Tree').item.json;

// Safely decode package.json (base64)
let packageJsonStr = '{}';
try {
  const pkgNode = $('Get package.json').item.json;
  if (pkgNode && pkgNode.content) {
    packageJsonStr = Buffer.from(pkgNode.content, 'base64').toString('utf8').substring(0, 2500);
  }
} catch(e) { packageJsonStr = '{}'; }

// Safely decode README.md (base64)
let readmeStr = 'No README found.';
try {
  const readmeNode = $('Get README.md').item.json;
  if (readmeNode && readmeNode.content) {
    readmeStr = Buffer.from(readmeNode.content, 'base64').toString('utf8').substring(0, 3000);
  }
} catch(e) { readmeStr = 'No README found.'; }

// Process file tree
const tree = Array.isArray(treeData.tree) ? treeData.tree.filter(f => f.type === 'blob') : [];
const total = tree.length;
const sourceExts = ['.ts', '.tsx', '.js', '.jsx', '.py', '.go', '.java', '.rs', '.rb', '.php', '.cs', '.cpp', '.c', '.vue', '.svelte'];
const sourceFiles = tree.filter(f => {
  const p = f.path.toLowerCase();
  return sourceExts.some(ext => p.endsWith(ext)) &&
    !p.includes('node_modules/') && !p.includes('vendor/') &&
    !p.includes('dist/') && !p.includes('build/') &&
    !p.includes('.min.') && !p.includes('__pycache__') &&
    !p.includes('.test.') && !p.includes('.spec.');
}).slice(0, 120);

// Group by top-level directory for module detection
const moduleMap = {};
sourceFiles.forEach(f => {
  const top = f.path.includes('/') ? f.path.split('/')[0] : 'root';
  if (!moduleMap[top]) moduleMap[top] = [];
  moduleMap[top].push(f.path);
});

const now = new Date().toISOString();
const lang = repoInfo.language || 'Unknown';
const desc = repoInfo.description || 'No description available.';
const fileListStr = sourceFiles.map(f => f.path).join('
').substring(0, 5000);

const systemPrompt = 'You are an expert software architect analyzing GitHub repositories for Branchy.io, a code architecture visualization and health analysis platform. Return ONLY valid raw JSON matching the exact schema provided — no markdown, no explanations, no code fences.';

const userPrompt = `Analyze this repository and return a JSON object matching EXACTLY the schema below.

## Repository Information
- Name: ${input.repoName}
- Owner: ${input.owner}
- URL: ${input.repoUrl}
- Description: ${desc}
- Primary Language: ${lang}
- Stars: ${repoInfo.stargazers_count || 0}
- Forks: ${repoInfo.forks_count || 0}
- Default Branch: ${repoInfo.default_branch || 'main'}
- Total Files: ${total}
- Source Files (filtered): ${sourceFiles.length}

## package.json
${packageJsonStr}

## README.md
${readmeStr}

## Module/Directory Map
${JSON.stringify(moduleMap, null, 2).substring(0, 3500)}

## Source File Paths
${fileListStr}

## Return this exact JSON structure (replace placeholder values with real analysis):
{
  "repoId": "${input.jobId}",
  "repoName": "${input.repoName}",
  "owner": "${input.owner}",
  "language": "<primary language>",
  "filesCount": ${total},
  "healthScore": 0,
  "analyzedAt": "${now}",
  "modules": [
    {
      "id": "module-slug",
      "name": "Module Name",
      "type": "core",
      "filePath": "src/index.ts",
      "loc": 120,
      "dependsOn": [],
      "usedBy": [],
      "summary": "Brief one-sentence description"
    }
  ],
  "insights": [
    { "type": "info", "text": "Insight text", "fileName": "file.ts" }
  ],
  "complexityByFile": [
    { "fileName": "file.ts", "filePath": "src/file.ts", "complexity": 40, "level": "medium" }
  ],
  "circularDeps": [
    { "id": "cycle-1", "chain": ["moduleA", "moduleB", "moduleA"] }
  ],
  "deadCode": [
    { "id": "dead-1", "moduleName": "OldUtil", "type": "function", "lastModified": "${now}", "linesCount": 45, "filePath": "src/utils/old.ts" }
  ],
  "onboardingGuide": {
    "sections": [
      { "title": "Project Overview", "type": "overview", "content": "<overview text>" },
      { "title": "Tech Stack", "type": "techStack", "content": { "frontend": [], "backend": [], "database": [], "devtools": [] } },
      { "title": "Project Structure", "type": "structure", "content": "<structure explanation>" },
      { "title": "Key Modules", "type": "modules", "content": "<modules overview>" },
      { "title": "Getting Started", "type": "gettingStarted", "content": "<setup steps>" },
      { "title": "Code Patterns", "type": "patterns", "content": "<architectural patterns>" },
      { "title": "Running Locally", "type": "runLocally", "content": { "steps": ["Clone the repository", "Install dependencies"], "commands": ["npm install", "npm run dev"] } }
    ],
    "generatedAt": "${now}"
  },
  "healthReport": {
    "overallScore": 0,
    "maintainability": 0,
    "testCoverage": 0,
    "documentation": 0,
    "issues": [
      {
        "id": "issue-1",
        "severity": "warning",
        "fileName": "file.ts",
        "filePath": "src/file.ts",
        "title": "Issue title",
        "description": "What the issue is",
        "suggestedFix": "How to fix it",
        "resolved": false
      }
    ]
  },
  "changelogs": []
}

Rules:
1. Generate 6-20 realistic modules reflecting actual directory structure
2. Generate 5-12 insights mixing warning/success/info/error types
3. complexityByFile: list 5-15 files with estimated complexity
4. circularDeps: detect if import patterns suggest cycles (empty array if none)
5. deadCode: identify 2-5 potentially unused items (empty array if none)
6. All numeric scores must be integers 0-100
7. onboardingGuide must contain ALL 7 section types
8. healthReport.issues: 3-8 real actionable issues
9. Return ONLY raw valid JSON — no markdown, no code fences, no explanation text`;

return [{
  json: {
    jobId: input.jobId,
    repoUrl: input.repoUrl,
    repoName: input.repoName,
    owner: input.owner,
    language: lang,
    filesCount: total,
    requestBody: {
      model: 'claude-opus-4-6',
      max_tokens: 8192,
      system: systemPrompt,
      messages: [{ role: 'user', content: userPrompt }]
    }
  }
}];

const prepared = $('Prepare AI Prompt').item.json;
const claudeResp = $input.first().json;
let analysisResult = null;
let success = false;
let errorMsg = '';

try {
  // Check for API-level errors
  if (claudeResp.error) {
    throw new Error('Anthropic API error: ' + (claudeResp.error.message || JSON.stringify(claudeResp.error)));
  }

  const content = claudeResp.content;
  if (!Array.isArray(content) || content.length === 0) {
    throw new Error('Empty or unexpected response structure from Claude API');
  }

  const textBlock = content.find(c => c.type === 'text');
  if (!textBlock || !textBlock.text) {
    throw new Error('No text content in Claude API response');
  }

  // Strip markdown code fences if present
  let jsonStr = textBlock.text.trim();
  jsonStr = jsonStr.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '').trim();

  analysisResult = JSON.parse(jsonStr);

  // Enforce required fields
  analysisResult.repoId = analysisResult.repoId || prepared.jobId;
  analysisResult.repoName = analysisResult.repoName || prepared.repoName;
  analysisResult.owner = analysisResult.owner || prepared.owner;
  analysisResult.language = analysisResult.language || prepared.language || 'Unknown';
  analysisResult.filesCount = analysisResult.filesCount || prepared.filesCount || 0;
  analysisResult.healthScore = Number(analysisResult.healthScore) || 0;
  analysisResult.analyzedAt = analysisResult.analyzedAt || new Date().toISOString();
  analysisResult.modules = Array.isArray(analysisResult.modules) ? analysisResult.modules : [];
  analysisResult.insights = Array.isArray(analysisResult.insights) ? analysisResult.insights : [];
  analysisResult.complexityByFile = Array.isArray(analysisResult.complexityByFile) ? analysisResult.complexityByFile : [];
  analysisResult.circularDeps = Array.isArray(analysisResult.circularDeps) ? analysisResult.circularDeps : [];
  analysisResult.deadCode = Array.isArray(analysisResult.deadCode) ? analysisResult.deadCode : [];
  analysisResult.changelogs = Array.isArray(analysisResult.changelogs) ? analysisResult.changelogs : [];

  if (!analysisResult.onboardingGuide || !Array.isArray(analysisResult.onboardingGuide.sections)) {
    analysisResult.onboardingGuide = { sections: [], generatedAt: new Date().toISOString() };
  }

  if (!analysisResult.healthReport || typeof analysisResult.healthReport.overallScore === 'undefined') {
    analysisResult.healthReport = {
      overallScore: analysisResult.healthScore || 70,
      maintainability: 70,
      testCoverage: 0,
      documentation: 50,
      issues: []
    };
  } else {
    analysisResult.healthReport.issues = Array.isArray(analysisResult.healthReport.issues)
      ? analysisResult.healthReport.issues
      : [];
  }

  success = true;

} catch(e) {
  errorMsg = e.message;
  // Minimal valid fallback so the job still saves
  analysisResult = {
    repoId: prepared.jobId,
    repoName: prepared.repoName,
    owner: prepared.owner,
    language: prepared.language || 'Unknown',
    filesCount: prepared.filesCount || 0,
    healthScore: 0,
    analyzedAt: new Date().toISOString(),
    modules: [],
    insights: [{ type: 'error', text: 'Analysis failed: ' + errorMsg }],
    complexityByFile: [],
    circularDeps: [],
    deadCode: [],
    changelogs: [],
    onboardingGuide: { sections: [], generatedAt: new Date().toISOString() },
    healthReport: { overallScore: 0, maintainability: 0, testCoverage: 0, documentation: 0, issues: [] }
  };
}

return [{
  json: {
    jobId: prepared.jobId,
    analysisResult,
    success,
    errorMsg
  }
}];
